# Gerado a partir de spark/sql/ (pasta sql removida; conteúdo embutido para paridade com dbt).

PIPELINE_SQL = 'WITH base AS (\n  SELECT * FROM glue_catalog.bronze.bronze_tasy_atend_paciente_unidade b\n  \n  WHERE b._bronze_loaded_at > (\n      SELECT COALESCE(MAX(s._silver_processed_at), CAST(\'1900-01-01\' AS TIMESTAMP))\n      FROM glue_catalog.silver.silver_tasy_atend_paciente_unidade s\n  )\n  \n)\n, latest_by_pk AS (\n  SELECT *\n  FROM (\n    SELECT\n        b.*\n      , ROW_NUMBER() OVER (\n          PARTITION BY b.nr_seq_interno\n          ORDER BY\n              CAST(COALESCE(b._cdc_ts_ms, 0) AS BIGINT) DESC\n            , CAST(COALESCE(b.__source_txid, 0) AS BIGINT) DESC\n        ) AS _rn\n    FROM base b\n  ) x\n  WHERE _rn = 1\n)\n, shaped AS (\n  SELECT\n      d.nr_seq_interno AS nr_seq_interno\n    , COALESCE(d.nr_atendimento, CAST(-1 AS BIGINT)) AS nr_atendimento\n    , COALESCE(d.nr_sequencia, CAST(-1 AS BIGINT)) AS nr_sequencia\n    , COALESCE(d.cd_setor_atendimento, CAST(-1 AS BIGINT)) AS cd_setor_atendimento\n    , COALESCE(d.cd_unidade_basica, CAST(-1 AS BIGINT)) AS cd_unidade_basica\n    , COALESCE(d.cd_unidade_compl, CAST(-1 AS BIGINT)) AS cd_unidade_compl\n    , CASE\n  WHEN d.dh_entrada_unidade IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN TRY_CAST(d.dh_entrada_unidade AS TIMESTAMP) IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN YEAR(TRY_CAST(d.dh_entrada_unidade AS TIMESTAMP)) >= 2900 THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  ELSE TRY_CAST(d.dh_entrada_unidade AS TIMESTAMP)\nEND AS dh_entrada_unidade\n    , CASE\n  WHEN d.dh_atualizacao IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN TRY_CAST(d.dh_atualizacao AS TIMESTAMP) IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN YEAR(TRY_CAST(d.dh_atualizacao AS TIMESTAMP)) >= 2900 THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  ELSE TRY_CAST(d.dh_atualizacao AS TIMESTAMP)\nEND AS dh_atualizacao\n    , INITCAP(COALESCE(NULLIF(TRIM(CAST(d.nm_usuario AS STRING)), \'\'), \'indefinido\')) AS nm_usuario\n    , COALESCE(d.cd_tipo_acomodacao, CAST(-1 AS BIGINT)) AS cd_tipo_acomodacao\n    , CASE\n  WHEN d.dh_saida_unidade IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN TRY_CAST(d.dh_saida_unidade AS TIMESTAMP) IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN YEAR(TRY_CAST(d.dh_saida_unidade AS TIMESTAMP)) >= 2900 THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  ELSE TRY_CAST(d.dh_saida_unidade AS TIMESTAMP)\nEND AS dh_saida_unidade\n    , COALESCE(d.nr_atend_dia, CAST(-1 AS BIGINT)) AS nr_atend_dia\n    , INITCAP(COALESCE(NULLIF(TRIM(CAST(d.ds_observacao AS STRING)), \'\'), \'indefinido\')) AS ds_observacao\n    , INITCAP(COALESCE(NULLIF(TRIM(CAST(d.nm_usuario_original AS STRING)), \'\'), \'indefinido\')) AS nm_usuario_original\n    , CASE\n  WHEN d.dh_saida_interno IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN TRY_CAST(d.dh_saida_interno AS TIMESTAMP) IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN YEAR(TRY_CAST(d.dh_saida_interno AS TIMESTAMP)) >= 2900 THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  ELSE TRY_CAST(d.dh_saida_interno AS TIMESTAMP)\nEND AS dh_saida_interno\n    , LOWER(COALESCE(NULLIF(TRIM(CAST(d.ie_passagem_setor AS STRING)), \'\'), \'i\')) AS ie_passagem_setor\n    , COALESCE(d.nr_acompanhante, CAST(-1 AS BIGINT)) AS nr_acompanhante\n    , LOWER(COALESCE(NULLIF(TRIM(CAST(d.ie_calcular_dif_diaria AS STRING)), \'\'), \'i\')) AS ie_calcular_dif_diaria\n    , COALESCE(d.nr_seq_motivo_transf, CAST(-1 AS BIGINT)) AS nr_seq_motivo_transf\n    , CASE\n  WHEN d.dh_entrada_real IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN TRY_CAST(d.dh_entrada_real AS TIMESTAMP) IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN YEAR(TRY_CAST(d.dh_entrada_real AS TIMESTAMP)) >= 2900 THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  ELSE TRY_CAST(d.dh_entrada_real AS TIMESTAMP)\nEND AS dh_entrada_real\n    , INITCAP(COALESCE(NULLIF(TRIM(CAST(d.nm_usuario_real AS STRING)), \'\'), \'indefinido\')) AS nm_usuario_real\n    , LOWER(COALESCE(NULLIF(TRIM(CAST(d.ie_radiacao AS STRING)), \'\'), \'i\')) AS ie_radiacao\n    , COALESCE(d.nr_seq_motivo_dif, CAST(-1 AS BIGINT)) AS nr_seq_motivo_dif\n    , COALESCE(d.nr_seq_mot_dif_diaria, CAST(-1 AS BIGINT)) AS nr_seq_mot_dif_diaria\n    , COALESCE(d.cd_unidade_externa, CAST(-1 AS BIGINT)) AS cd_unidade_externa\n    , CASE\n  WHEN d.dh_alta_medico_setor IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN TRY_CAST(d.dh_alta_medico_setor AS TIMESTAMP) IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN YEAR(TRY_CAST(d.dh_alta_medico_setor AS TIMESTAMP)) >= 2900 THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  ELSE TRY_CAST(d.dh_alta_medico_setor AS TIMESTAMP)\nEND AS dh_alta_medico_setor\n    , COALESCE(d.cd_motivo_alta_setor, CAST(-1 AS BIGINT)) AS cd_motivo_alta_setor\n    , COALESCE(d.cd_procedencia_setor, CAST(-1 AS BIGINT)) AS cd_procedencia_setor\n    , COALESCE(d.nr_seq_motivo_int, CAST(-1 AS BIGINT)) AS nr_seq_motivo_int\n    , COALESCE(d.nr_seq_motivo_int_sub, CAST(-1 AS BIGINT)) AS nr_seq_motivo_int_sub\n    , COALESCE(d.nr_seq_motivo_perm, CAST(-1 AS BIGINT)) AS nr_seq_motivo_perm\n    , CASE\n  WHEN d.dh_atualizacao_nrec IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN TRY_CAST(d.dh_atualizacao_nrec AS TIMESTAMP) IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN YEAR(TRY_CAST(d.dh_atualizacao_nrec AS TIMESTAMP)) >= 2900 THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  ELSE TRY_CAST(d.dh_atualizacao_nrec AS TIMESTAMP)\nEND AS dh_atualizacao_nrec\n    , INITCAP(COALESCE(NULLIF(TRIM(CAST(d.nm_usuario_nrec AS STRING)), \'\'), \'indefinido\')) AS nm_usuario_nrec\n    , COALESCE(d.nr_cirurgia, CAST(-1 AS BIGINT)) AS nr_cirurgia\n    , COALESCE(d.nr_seq_pepo, CAST(-1 AS BIGINT)) AS nr_seq_pepo\n    , COALESCE(d.nr_seq_agrupamento, CAST(-1 AS BIGINT)) AS nr_seq_agrupamento\n    , COALESCE(\n  ROUND(CAST(d.qt_tempo_prev AS DECIMAL(38, 6)), 2),\n  CAST(-1.0 AS DECIMAL(38, 2))\n) AS qt_tempo_prev\n    , COALESCE(d.nr_seq_unid_ant, CAST(-1 AS BIGINT)) AS nr_seq_unid_ant\n    , CASE\n  WHEN d.dh_saida_temporaria IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN TRY_CAST(d.dh_saida_temporaria AS TIMESTAMP) IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN YEAR(TRY_CAST(d.dh_saida_temporaria AS TIMESTAMP)) >= 2900 THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  ELSE TRY_CAST(d.dh_saida_temporaria AS TIMESTAMP)\nEND AS dh_saida_temporaria\n    , CASE\n  WHEN d.dh_retorno_saida_temporaria IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN TRY_CAST(d.dh_retorno_saida_temporaria AS TIMESTAMP) IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN YEAR(TRY_CAST(d.dh_retorno_saida_temporaria AS TIMESTAMP)) >= 2900 THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  ELSE TRY_CAST(d.dh_retorno_saida_temporaria AS TIMESTAMP)\nEND AS dh_retorno_saida_temporaria\n    , COALESCE(NULLIF(TRIM(CAST(d.id_leito_temp_cross AS STRING)), \'\'), "\'ind\'") AS id_leito_temp_cross\n    , COALESCE(d.cd_departamento, CAST(-1 AS BIGINT)) AS cd_departamento\n    , COALESCE(d.cd_procedencia_atend, CAST(-1 AS BIGINT)) AS cd_procedencia_atend\n    , COALESCE(d.nr_seq_classif_esp, CAST(-1 AS BIGINT)) AS nr_seq_classif_esp\n    , LOWER(COALESCE(NULLIF(TRIM(CAST(d.ie_anzics_generated AS STRING)), \'\'), \'i\')) AS ie_anzics_generated\n    , COALESCE(d.cd_evolucao, CAST(-1 AS BIGINT)) AS cd_evolucao\n    , CASE\n  WHEN d.dh_est_return IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN TRY_CAST(d.dh_est_return AS TIMESTAMP) IS NULL THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  WHEN YEAR(TRY_CAST(d.dh_est_return AS TIMESTAMP)) >= 2900 THEN TIMESTAMP \'1900-01-01 00:00:00\'\n  ELSE TRY_CAST(d.dh_est_return AS TIMESTAMP)\nEND AS dh_est_return\n    \n    , d._is_deleted AS _is_deleted\n    , d._cdc_op AS _cdc_op\n    , d._cdc_event_at AS _cdc_event_at\n    , d._cdc_ts_ms AS _cdc_ts_ms\n    , d._row_hash AS _bronze_row_hash\n    , d._bronze_loaded_at AS _bronze_loaded_at\n    , from_utc_timestamp(current_timestamp(), \'America/Sao_Paulo\') AS _silver_processed_at\n    , CAST(uuid() AS STRING) AS _dbt_invocation_id\n  FROM latest_by_pk d\n)\n, final AS (\n  SELECT *\n  FROM shaped\n  WHERE NOT _is_deleted\n)\nSELECT * FROM final\n'
